import scala.collection.immutable.List

object Solution {
  /**
    * Calculates the maximum integer value that can be represented by concatenating
    * the binary fragments in some order, modulo 10^9 + 7.
    * 
    * @param nums1 Array of '1' counts for each fragment.
    * @param nums0 Array of '0' counts for each fragment.
    * @return The maximum integer value modulo 10^9 + 7.
    */
  def nums1(nums1: Array[Long]): Long = {
    val n = nums1.length
    val MOD: Long = 1000000007L

    // 1. Construct a comparable representation for each fragment.
    // The comparison rule is: fragment A should come before fragment B if 
    // A concatenated with B results in a larger number than B concatenated with A.
    // This is equivalent to comparing A+B with B+A lexicographically.

    // Store pairs (nums1[i], nums0[i])
    val fragments = (0 until n).map { i => (nums1(i), nums0(i)) }

    // Custom comparator: (a1, a0) vs (b1, b0)
    // Compare (a1*2^a0 + a0) with (b1*2^b0 + b0) is complex because of varying lengths.
    // We use the lexicographical comparison of the actual strings they form:
    // S_A = "1" * a1 + "0" * a0
    // S_B = "1" * b1 + "0" * b0
    // We want to sort such that if S_A + S_B > S_B + S_A, then A comes before B.

    val sortedFragments = fragments.sortBy { (a1, a0) =>
      // The comparison logic is: we want to sort in descending order based on the 
      // "preference" of the string.
      // If S_A + S_B > S_B + S_A, A should come before B (i.e., A is "greater").
      // Standard sort sorts ascendingly, so we use reversed comparison or custom logic.

      // We define a custom comparison function that returns:
      // Negative if A < B (A comes after B)
      // Positive if A > B (A comes before B)
      // Zero if A = B

      // Since sortBy uses a natural ordering, we need a way to map the required order 
      // (descending by preference) to an ascending sort key.

      // Let's use a stable sort approach or implement the comparator directly.

      // Using a custom comparator approach via sortWith

      val comparator = (a: (Long, Long), b: (Long, Long)) => {
        val sa = "1" * a._1 + "0" * a._2
        val sb = "1" * b._1 + "0" * b._2

        // Compare sa + sb vs sb + sa lexicographically
        val s_ab = sa + sb
        val s_ba = sb + sa

        s_ab.compareTo(s_ba) // Positive if A+B > B+A, which means A should come before B.
      }

      // To use sortBy, we need a comparable element. Sorting by a derived "value" is hard.
      // We must use sortWith(comparator).
    }

    val sortedFragmentsWithComparator = fragments.sorted(
      (a: (Long, Long), b: (Long, Long)) => {
        val sa = "1" * a._1 + "0" * a._2
        val sb = "1" * b._1 + "0" * b._2

        // If A+B > B+A, then A is preferred over B, so A should come first (return negative in ascending sort context if we were sorting ascendingly by preference, but here we want A first).
        // Standard sort: If comparator(A, B) < 0, A comes before B.
        // We want A before B if A+B > B+A.

        val s_ab = sa + sb
        val s_ba = sb + sa

        // If s_ab > s_ba, we want A before B, so return negative.
        s_ba.compareTo(s_ab) // If s_ab > s_ba, then s_ba < s_ab, returns negative.
      }
    )

    // 2. Calculate the value of the concatenated string modulo MOD.
    var result: Long = 0L
    var powerOf2: Long = 1L

    // The total length of the string is fixed, but the contribution of each fragment depends on its position.
    // If we concatenate S1, S2, ..., Sk, the total value is:
    // Value(S1) * 2^(Length(S2) + ... + Length(Sk)) + Value(S2) * 2^(Length(S3) + ... + Length(Sk)) + ... + Value(Sk)

    // A simpler way: iterate through the sorted fragments. For each fragment Si, 
    // its contribution is Value(Si) * 2^(Total Length of all subsequent fragments).

    // Pre-calculate the total length of all subsequent fragments.
    val totalLength = fragments.map { (a1, a0) => a1 + a0 }.sum

    // We iterate from the first fragment (most significant) to the last.
    var currentLengthSuffix: Long = 0L // Length of all fragments *after* the current one

    // We process the fragments in reverse order of concatenation (i.e., from the last fragment to the first)
    // to easily track the suffix length.

    var finalResult: Long = 0L
    var currentPowerOf2: Long = 1L // Represents 2^0, 2^1, 2^2, ... as we go backward

    for ((i, (a1, a0)) <- sortedFragmentsWithComparator.zip(0 until n).reverse) {
        val len = a1 + a0

        // The current fragment contributes Value(fragment) * 2^(currentLengthSuffix)

        // Value of the current fragment = (2^a1 - 1) * 2^a0
        // Where (2^a1 - 1) is the value of a1 ones.

        // Calculate (2^a1 - 1) mod MOD
        var valOnes: Long = 0L
        if (a1 > 0) {
            // Use modular exponentiation for 2^a1
            var twoPowA1: Long = 1L
            var base: Long = 2L
            var exp: Long = a1
            while (exp > 0) {
                if (exp % 2 == 1L) {
                    twoPowA1 = (twoPowA1 * base) % MOD
                }
                base = (base * base) % MOD
                exp /= 2
            }
            // valOnes = (2^a1 - 1) mod MOD
            valOnes = (twoPowA1 - 1 + MOD) % MOD
        }

        // Calculate 2^a0 mod MOD
        var twoPowA0: Long = 1L
        var base2: Long = 2L
        var exp2: Long = a0
        while (exp2 > 0) {
            if (exp2 % 2 == 1L) {
                twoPowA0 = (twoPowA0 * base2) % MOD
            }
            base2 = (base2 * base2) % MOD
            exp2 /= 2
        }

        // Value(fragment) = valOnes * twoPowA0 mod MOD
        val fragmentValue: Long = (valOnes * twoPowA0) % MOD

        // Contribution = fragmentValue * 2^currentLengthSuffix mod MOD
        val contribution: Long = (fragmentValue * currentPowerOf2) % MOD

        // Add to result
        finalResult = (finalResult + contribution) % MOD

        // Update currentPowerOf2 for the next (more significant) fragment
        // Next power of 2 needs to be multiplied by 2^len
        // currentPowerOf2_next = currentPowerOf2 * 2^len

        // Calculate 2^len mod MOD
        var twoPowLen: Long = 1L
        var baseLen: Long = 2L
        var expLen: Long = len
        while (expLen > 0) {
            if (expLen % 2 == 1L) {
                twoPowLen = (twoPowLen * baseLen) % MOD
            }
            baseLen = (baseLen * baseLen) % MOD
            expLen /= 2
        }

        currentPowerOf2 = (currentPowerOf2 * twoPowLen) % MOD

        // Update suffix length
        currentLengthSuffix += len
    }

    finalResult
  }
}
