import scala.math.pow

object Solution {
  def nums1(nums1: Array[Long]): Long = {
    val n = nums1.length
    val mod = 1_000_000_007L

    // 1. Combine (nums1[i], nums0[i]) pairs and calculate the sorting key.
    // The sorting criterion should prioritize segments that result in a larger number when placed earlier.
    // For two segments S_i and S_j, S_i should come before S_j if S_i + S_j > S_j + S_i (in terms of binary value).
    // Let S_i = 1...10...0 (L_i ones, R_i zeros) and S_j = 1...10...0 (L_j ones, R_j zeros).
    // Comparison of S_i + S_j vs S_j + S_i is equivalent to comparing:
    // (L_i * 2^(L_j+R_j) + (2^L_i - 1) * 2^R_i) vs (L_j * 2^(L_i+R_i) + (2^L_j - 1) * 2^R_j)
    // A simpler, standard greedy approach for this type of problem is to compare based on the
    // relative magnitude contribution. The segment with more '1's should generally come first.

    // Since the problem asks for the largest *integer* value, we compare based on the lexicographical order
    // of the resulting string, which is equivalent to comparing the numbers formed by the sequence.
    // For two segments A and B, A comes before B if A+B > B+A.

    case class Segment(ones: Long, zeros: Long)

    val segments = (0 until n).map { i =>
      Segment(nums1(i), nums0(i))
    }.toArray

    // Custom comparison function for sorting segments
    // We want to sort in descending order based on the custom comparison: A should come before B if A+B > B+A.
    val comparator = new Comparator[Segment] {
      def compare(a: Segment, b: Segment): Int = {
        // Check if A + B > B + A
        // A = 1^La 0^Ra, B = 1^Lb 0^Rb
        // A+B = 1^La 0^Ra 1^Lb 0^Rb
        // B+A = 1^Lb 0^Rb 1^La 0^Ra

        // Since the total number of bits is fixed, the comparison boils down to where the first difference appears.
        // The comparison of two concatenated strings S1S2 vs S2S1 is the correct greedy approach.

        // String representation comparison for safety, although computationally heavy for large inputs,
        // it reflects the mathematical requirement. Given the constraints (Total length <= 2*10^5), string comparison is feasible.

        val strA = "1".repeat((a.ones).toInt) + "0".repeat((a.zeros).toInt)
        val strB = "1".repeat((b.ones).toInt) + "0".repeat((b.zeros).toInt)

        val strA_B = strA + strB
        val strB_A = strB + strA

        strB_A.compareTo(strA_B) // We want descending order (strA+strB > strB+strA) -> return negative if strA+strB is greater
      }
    }

    // Sort segments using the custom comparator (descending order based on the comparison logic)
    val sortedSegments = segments.sortBy(s => s) { (a: Segment, b: Segment) =>
        val strA = "1".repeat((a.ones).toInt) + "0".repeat((a.zeros).toInt)
        val strB = "1".repeat((b.ones).toInt) + "0".repeat((b.zeros).toInt)

        val strA_B = strA + strB
        val strB_A = strB + strA

        // If strA_B > strB_A, we want A to come before B (descending sort order).
        // String comparison returns positive if the first string is lexicographically greater.
        // For descending sort (like Java's Collections.reverseOrder()), we return -1 if A should come before B.
        strB_A.compareTo(strA_B) // Returns negative if strA_B > strB_A
    }

    // 2. Concatenate the sorted segments and calculate the resulting number modulo MOD.
    var result: Long = 0L
    var currentPowerOf2: Long = 1L

    // Iterate through the sorted segments in reverse order to easily calculate positional weight,
    // or iterate forwards and use powers of 2 carefully. Forward iteration is cleaner.

    // Total length L = sum(nums1[i] + nums0[i])
    // The segment at index k (0-indexed) contributes its value shifted by the length of all subsequent segments.

    // A simpler way: process segments one by one, updating the total value.

    for (segment in sortedSegments) {
      val ones = segment.ones
      val zeros = segment.zeros
      val segmentLength = ones + zeros

      // The value contributed by this segment is:
      // (2^ones - 1) * 2^zeros (if zeros > 0) + (if ones > 0, the leading 1s contribute)

      // Value of 1^ones 0^zeros in base 10:
      // It is equivalent to (2^segmentLength - 2^zeros)

      var segmentValue: Long = 0L

      // Calculate 2^ones - 1 (value of 1^ones)
      var valueOnes: Long = 1L
      for (i <- 1 to ones) {
        valueOnes = (valueOnes * 2) % mod
      }
      valueOnes = (valueOnes - 1 + mod) % mod // (2^ones - 1) mod MOD

      // Multiply by 2^zeros (shift left by zeros positions)
      var shiftFactor: Long = 1L
      for (i <- 1 to zeros) {
        shiftFactor = (shiftFactor * 2) % mod
      }

      segmentValue = (valueOnes * shiftFactor) % mod

      // Update the total result: result = (result * 2^segmentLength + segmentValue) mod MOD
      // Wait, this formula is for appending a new number, not concatenating binary strings.

      // Correct update rule for string concatenation S_current + S_new:
      // Value(S_current + S_new) = Value(S_current) * 2^(Length(S_new)) + Value(S_new)

      val lengthNew = segmentLength

      // 1. Calculate 2^lengthNew mod MOD
      var powerOf2Len: Long = 1L
      for (i <- 1 to lengthNew) {
        powerOf2Len = (powerOf2Len * 2) % mod
      }

      // 2. Calculate the value of the current segment (1^ones 0^zeros) mod MOD
      // Value = (2^ones - 1) * 2^zeros
      var currentSegmentValue: Long = 0L

      // 2^ones - 1 mod MOD
      var twoPowOnes: Long = 1L
      for (i <- 1 to ones) {
        twoPowOnes = (twoPowOnes * 2) % mod
      }
      twoPowOnes = (twoPowOnes - 1 + mod) % mod

      // 2^zeros mod MOD
      var twoPowZeros: Long = 1L
      for (i <- 1 to zeros) {
        twoPowZeros = (twoPowZeros * 2) % mod
      }

      currentSegmentValue = (twoPowOnes * twoPowZeros) % mod

      // 3. Update total result
      // result = (result * 2^lengthNew + currentSegmentValue) mod MOD
      result = (result * powerOf2Len) % mod
      result = (result + currentSegmentValue) % mod
    }

    result
  }
}
